type AppState =
  | { status: 'landing' }
  | { status: 'loading'; url: string }
  | { status: 'error'; message: string }
  | { status: 'ready'; story: Story; currentChapter: number };

export default function App() {
  const [state, setState] = useState<AppState>({ status: 'landing' });

  useEffect(() => {
    const { storyUrl } = parseStoryUrl();
    if (storyUrl) {
      setState({ status: 'loading', url: storyUrl });
      fetchStory(storyUrl)
        .then(story => {
          setState({ status: 'ready', story, currentChapter: 0 });
          saveRecent(story);
        })
        .catch(err => {
          setState({ status: 'error', message: err.message });
        });
    }
  }, []);

const navigateChapter = useCallback((index: number) => {
  if (state.status === 'ready') {
    const clamped = Math.max(0, Math.min(index, state.story.chapters.length - 1));
    setState({ ...state, currentChapter: clamped });
  }
}, [state]);

// Keyboard navigation
useEffect(() => {
  if (state.status !== 'ready') return;

  const handler = (e: KeyboardEvent) => {
    // Don't capture when typing in input
    if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;

    switch (e.key) {
      case 'ArrowLeft':
      case 'h':
        navigateChapter(state.currentChapter - 1);
        break;
      case 'ArrowRight':
      case 'l':
        navigateChapter(state.currentChapter + 1);
        break;
      case 'Home':
        navigateChapter(0);
        break;
      case 'End':
        navigateChapter(state.story.chapters.length - 1);
        break;
      default:
        if (e.key >= '1' && e.key <= '9') {
          navigateChapter(parseInt(e.key) - 1);
        }
    }
  };

  window.addEventListener('keydown', handler);
  return () => window.removeEventListener('keydown', handler);
}, [state, navigateChapter]);

export interface ManifestEntry {
  id: string;
  title: string;
  arxivId?: string;
  createdAt: string;
}

export interface Manifest {
  stories: ManifestEntry[];
}

export async function fetchManifest(url: string): Promise<Manifest> {
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`Failed to fetch manifest: ${response.status}`);
  }
  return response.json();
}

